    private List<String> getMatchFileNames(RecoveryFilterVO filterVO, String apname) {
            String recoverDirPath = String.format("cust/data/" + apname + "/removed");
            List<String> matchfileNames = getDirFileNames(recoverDirPath);

            String keyword = filterVO.getKeyword();
            if(keyword != null){
                if(matchfileNames != null && !matchfileNames.isEmpty()){
                    matchfileNames = getMatchFile(new RecoveryKeywordScan(keyword), apname, matchfileNames);
                }
            }

            Long dtStart = filterVO.getDtStart();
            if(dtStart != null){
                if(matchfileNames != null && !matchfileNames.isEmpty()){
                    matchfileNames = getMatchFile(new RecoveryTimeStartScan(dtStart), apname, matchfileNames);
                }
            }

            Long dtEnd = filterVO.getDtEnd();
            if(dtEnd != null){
                if(matchfileNames != null && !matchfileNames.isEmpty()){
                    matchfileNames = getMatchFile(new RecoveryTimeEndScan(dtEnd), apname, matchfileNames);
                }
            }

            String pathSheet = filterVO.getPathSheet();
            if(pathSheet != null){
                int sheetIndex = Integer.parseInt(pathSheet.split("/")[1]);
                String path = pathSheet.split("/")[0];

                NUIForm form = AppManager.getFormPage(apname, "/" + path, sheetIndex);
                int domainId = form.getRootDomainId();

                matchfileNames = getMatchFile(new RecoveryDomainIdScan(domainId, sheetIndex), apname, matchfileNames);
            }

            String editorID = filterVO.getEditorId();
            if(editorID != null){
                if(matchfileNames != null && !matchfileNames.isEmpty()){
                    matchfileNames = getMatchFile(new RecoveryEditorScan(editorID), apname, matchfileNames);
                }
            }

        String dataUrl = filterVO.getDataUrl();
        if(dataUrl != null){
            if(matchfileNames != null && !matchfileNames.isEmpty()){
                matchfileNames = getMatchFile(new RecoveryDataUrlScan(dataUrl), apname, matchfileNames);
            }
        }


        return matchfileNames;
    }

    private void printRecord(HistoryRecord record, String apname, JspWriter out, RagicBundle bundle, User user, boolean noMoreCreate, RagicDateFormatter rdf) {
        StringBuilder output = new StringBuilder();

        String loggedTime = rdf.format(bundle.convertTime(new Date(record.getTimestamp())));
        String contentStr = "";
        JSONObject content = null;
        try {
            content = new JSONObject(record.getContent());
            String[] params = record.getPathSheet().split("/");
            NUIForm thisForm = AppManager.getFormPage(apname, "/" + params[1], params[2]);

            String recordType = content.optString("type");

            if(!"delete".equals(recordType) && !"massDelete".equals(recordType) && !"reference_subtable_delete".equals(recordType)) return; // [issue#08106]


            if (recordType.startsWith("mass")) {
                contentStr = record.processHistoryContentJSON(content, bundle, thisForm, Const.NONODE, true, false, user, HistoryRecordFormatType.HTML_HISTORY);
            } else {
                contentStr = record.processHistoryContentJSON(content, bundle, thisForm, Const.NONODE, false, true, user, HistoryRecordFormatType.HTML_HISTORY);
            }
        } catch (Exception e) {
            String contentTmp = record.printDeleteSheetOrReportContent(bundle);
            contentStr = Encoder.sanitizeExceptionHistoryContent(contentTmp);
        } finally {
            output.append("<div class='historyRecord' onclick='closeUL(this);'>")
                    .append("<span style='color:#AAAAAA'>").append(loggedTime).append("</span> ")
                    .append(contentStr);
        }

        if (record.getHistoryType() == 1) {
            if (noMoreCreate) {
                output.append("&nbsp&nbsp<a href='javascript:void(0);' onclick='floatWin(null,\"Not enough sheets allowed in your account.<br/>Will need to <a style=float:none href=/" + apname + "/admin>upgrade your account</a> for more sheets.\");'>" + bundle.getString("restore") + "</a>");
            } else {
                output.append("&nbsp&nbsp<a href='javascript:void(0);' onclick='recoverMenu(\"" + apname + "\",\"" + record.getTimestampNodeId() + "\")'>" + bundle.getString("restore") + "</a>");
            }
            output.append("&nbsp|&nbsp<a href='javascript:void(0);' onclick='deleteMenuPerm(\"" + apname + "\",\"" + record.getTimestampNodeId() + "\")'>" + bundle.getString("delete") + "</a></div>");
        } else {
            if (content != null) {
                boolean formExists = true;
                String formURL = content.optString("url", "");
                String sheetName = content.optString("sheetName", "");
                if (!formURL.isEmpty()) {

                    //apname might change, update formURL
                    String[] sec = formURL.split("/");
                    sec[0] = apname;
                    formURL = String.join("/", sec);

                    try{
                        APIQuery q = new APIQuery("/" + formURL);
                        if (q.getForm() == null) formExists = false;
                    }
                    catch(Exception e){
                        ExceptionManager.getInstance().processException(e,content.toString(),user);
                        formExists=false;
                    }
                } else {
                    formExists = false;
                }
                if (formExists) {
                    output.append("&nbsp&nbsp<a href='javascript:void(0);' onclick='recoverEntry(\"" + apname + "\",\"" + record.getTransId() + "\")'>" + bundle.getString("restore") + "</a>")
                            .append("&nbsp|&nbsp<a href='javascript:void(0);' onclick='deleteEntryPerm(\"" + apname + "\",\"" + record.getTransId() + "\")'>" + bundle.getString("delete") + "</a></div>");
                } else {
                    output.append("&nbsp&nbsp<a href='javascript:void(0);' onclick='floatWin(null, \"" + bundle.getString("restoreFailed_sheetNotExists", new Object[]{sheetName}) + "\")'>" + bundle.getString("restore") + "</a>")
                            .append("&nbsp|&nbsp<a href='javascript:void(0);' onclick='deleteEntryPerm(\"" + apname + "\",\"" + record.getTransId() + "\")'>" + bundle.getString("delete") + "</a></div>");
                }
            } else {
                // old format
                output.append("&nbsp&nbsp<a href='javascript:void(0);' onclick='recoverEntry(\"" + apname + "\",\"" + record.getTransId() + "\")'>" + bundle.getString("restore") + "</a>")
                        .append("&nbsp|&nbsp<a href='javascript:void(0);' onclick='deleteEntryPerm(\"" + apname + "\",\"" + record.getTransId() + "\")'>" + bundle.getString("delete") + "</a></div>");
            }
        }

        try {
            out.println(output.toString());
        } catch (IOException e) {
            ExceptionManager.getInstance().processException(e);
        }
    }

    private List<String> getDirFileNames(String path){
        File fileDir = Paths.get(path).toFile();

       return RecoveryUtil.getFilesForFolder(fileDir);
    }

    private List<String> getMatchFile(RecoveryScan scanService, String apname, List<String> matchFiles){
        return scanService.searchAllMatchFile(apname, matchFiles);
    }



